import base64
import json
import sys
import os
import urllib.request
from http.server import BaseHTTPRequestHandler
from google.protobuf import json_format
import jwt
from jwt.algorithms import RSAAlgorithm

# Add generated proto path at runtime (committed to repo, generated by buf generate)
_gen_path = os.path.join(os.path.dirname(__file__), "..", "gen", "python", "sup")
if _gen_path not in sys.path:
    sys.path.insert(0, _gen_path)

import sup_pb2  # noqa: E402 — path inserted above

# Add lib/ to path for domain and adapters modules
_lib_path = os.path.join(os.path.dirname(__file__), "..", "lib")
if _lib_path not in sys.path:
    sys.path.insert(0, _lib_path)

from domain.greeting import greet_sup  # noqa: E402
from adapters.postgres.greeting_store import PostgresGreetingStore  # noqa: E402

_store = PostgresGreetingStore()
_jwks_cache: dict | None = None


def _jwks_url_from_publishable_key(key: str) -> str:
    for prefix in ("pk_test_", "pk_live_"):
        if key.startswith(prefix):
            key = key[len(prefix):]
            break
    domain = base64.b64decode(key + "==").decode("utf-8").rstrip("$")
    return f"https://{domain}/.well-known/jwks.json"


def _get_jwks() -> dict:
    global _jwks_cache
    if _jwks_cache is None:
        key = os.environ.get("VITE_CLERK_PUBLISHABLE_KEY", "")
        if not key:
            raise RuntimeError("VITE_CLERK_PUBLISHABLE_KEY not set")
        url = _jwks_url_from_publishable_key(key)
        with urllib.request.urlopen(url) as resp:
            _jwks_cache = json.loads(resp.read())
    return _jwks_cache


def _require_auth(auth_header: str) -> None:
    if not auth_header.startswith("Bearer "):
        raise PermissionError("missing Authorization header")
    token = auth_header[len("Bearer "):]
    header = jwt.get_unverified_header(token)
    kid = header.get("kid")
    jwks = _get_jwks()
    key_data = next((k for k in jwks["keys"] if k.get("kid") == kid), None)
    if key_data is None:
        raise PermissionError("no matching key found")
    public_key = RSAAlgorithm.from_jwk(key_data)
    jwt.decode(token, public_key, algorithms=["RS256"])


class handler(BaseHTTPRequestHandler):
    """Vercel Python serverless handler for SupService.SaySup (Connect-RPC unary over JSON)."""

    def do_POST(self):
        auth_header = self.headers.get("Authorization", "")
        try:
            _require_auth(auth_header)
        except PermissionError as e:
            error = json.dumps({"code": "unauthenticated", "message": str(e)}).encode()
            self.send_response(401)
            self.send_header("Content-Type", "application/json")
            self.send_header("Content-Length", str(len(error)))
            self.end_headers()
            self.wfile.write(error)
            return
        except RuntimeError as e:
            error = json.dumps({"code": "internal", "message": str(e)}).encode()
            self.send_response(500)
            self.send_header("Content-Type", "application/json")
            self.send_header("Content-Length", str(len(error)))
            self.end_headers()
            self.wfile.write(error)
            return

        content_length = int(self.headers.get("Content-Length", 0))
        body = self.rfile.read(content_length)

        try:
            req = json_format.Parse(body, sup_pb2.SupRequest())
        except Exception:
            error = json.dumps({"code": "invalid_argument", "message": "Invalid request body"}).encode()
            self.send_response(400)
            self.send_header("Content-Type", "application/json")
            self.send_header("Content-Length", str(len(error)))
            self.end_headers()
            self.wfile.write(error)
            return

        message = greet_sup(req.name, _store)
        resp = sup_pb2.SupResponse(message=message)
        result = json_format.MessageToJson(resp, preserving_proto_field_name=True).encode()
        self.send_response(200)
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", str(len(result)))
        self.end_headers()
        self.wfile.write(result)

    def do_GET(self):
        error = json.dumps({"code": "unimplemented", "message": "Method not allowed"}).encode()
        self.send_response(405)
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", str(len(error)))
        self.end_headers()
        self.wfile.write(error)
